import React, { useState, useEffect } from 'react';
import Sidebar from '../components/Sidebar';

const MyBookings = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  // Mock booking data
  const mockBookings = [
    {
      id: 1,
      carName: 'Tesla Model S',
      carImage: 'https://via.placeholder.com/100x60?text=Tesla',
      startDate: '2024-01-15',
      endDate: '2024-01-20',
      pickupLocation: 'Downtown Office',
      status: 'active',
      totalPrice: 750,
      bookingDate: '2024-01-10'
    },
    {
      id: 2,
      carName: 'BMW X5',
      carImage: 'https://via.placeholder.com/100x60?text=BMW',
      startDate: '2024-01-01',
      endDate: '2024-01-05',
      pickupLocation: 'Airport Branch',
      status: 'completed',
      totalPrice: 600,
      bookingDate: '2023-12-28'
    },
    {
      id: 3,
      carName: 'Mercedes C-Class',
      carImage: 'https://via.placeholder.com/100x60?text=Mercedes',
      startDate: '2024-02-01',
      endDate: '2024-02-03',
      pickupLocation: 'Downtown Office',
      status: 'pending',
      totalPrice: 200,
      bookingDate: '2024-01-20'
    },
    {
      id: 4,
      carName: 'Audi A4',
      carImage: 'https://via.placeholder.com/100x60?text=Audi',
      startDate: '2023-12-10',
      endDate: '2023-12-15',
      pickupLocation: 'Airport Branch',
      status: 'cancelled',
      totalPrice: 400,
      bookingDate: '2023-12-05'
    }
  ];

  useEffect(() => {
    // Simulate loading data
    setTimeout(() => {
      setBookings(mockBookings);
      setLoading(false);
    }, 500);
  }, []);

  const handleCancelBooking = (bookingId) => {
    if (window.confirm('Are you sure you want to cancel this booking?')) {
      setBookings(bookings.map(booking => 
        booking.id === bookingId 
          ? { ...booking, status: 'cancelled' } 
          : booking
      ));
    }
  };

  const filteredBookings = bookings.filter(booking => {
    if (filter === 'all') return true;
    return booking.status === filter;
  });

  const getStatusBadge = (status) => {
    const statusClasses = {
      active: 'status-active',
      pending: 'status-pending',
      completed: 'status-completed',
      cancelled: 'status-cancelled'
    };
    return (
      <span className={`status-badge ${statusClasses[status]}`}>
        {status.charAt(0).toUpperCase() + status.slice(1)}
      </span>
    );
  };

  return (
    <div className="dashboard-page">
      <Sidebar />
      
      <div className="dashboard-content">
        <div className="page-header">
          <h1>My Bookings</h1>
          <p>View and manage your car rentals</p>
        </div>

        {/* Filter Tabs */}
        <div className="filter-tabs">
          <button 
            className={`filter-tab ${filter === 'all' ? 'active' : ''}`}
            onClick={() => setFilter('all')}
          >
            All ({bookings.length})
          </button>
          <button 
            className={`filter-tab ${filter === 'active' ? 'active' : ''}`}
            onClick={() => setFilter('active')}
          >
            Active ({bookings.filter(b => b.status === 'active').length})
          </button>
          <button 
            className={`filter-tab ${filter === 'pending' ? 'active' : ''}`}
            onClick={() => setFilter('pending')}
          >
            Pending ({bookings.filter(b => b.status === 'pending').length})
          </button>
          <button 
            className={`filter-tab ${filter === 'completed' ? 'active' : ''}`}
            onClick={() => setFilter('completed')}
          >
            Completed ({bookings.filter(b => b.status === 'completed').length})
          </button>
          <button 
            className={`filter-tab ${filter === 'cancelled' ? 'active' : ''}`}
            onClick={() => setFilter('cancelled')}
          >
            Cancelled ({bookings.filter(b => b.status === 'cancelled').length})
          </button>
        </div>

        {/* Bookings List */}
        {loading ? (
          <div className="loading">Loading bookings...</div>
        ) : filteredBookings.length === 0 ? (
          <div className="empty-state">
            <p>No bookings found</p>
          </div>
        ) : (
          <div className="bookings-list">
            {filteredBookings.map(booking => (
              <div key={booking.id} className="booking-card">
                <div className="booking-car-image">
                  <img 
                    src={booking.carImage} 
                    alt={booking.carName}
                    onError={(e) => {
                      e.target.src = 'https://via.placeholder.com/100x60?text=Car';
                    }}
                  />
                </div>
                
                <div className="booking-details">
                  <h3>{booking.carName}</h3>
                  <div className="booking-info">
                    <p><strong>Pickup:</strong> {booking.startDate}</p>
                    <p><strong>Return:</strong> {booking.endDate}</p>
                    <p><strong>Location:</strong> {booking.pickupLocation}</p>
                    <p><strong>Booked on:</strong> {booking.bookingDate}</p>
                  </div>
                </div>

                <div className="booking-actions">
                  <div className="booking-price">
                    <span className="price-label">Total</span>
                    <span className="price-value">${booking.totalPrice}</span>
                  </div>
                  
                  {getStatusBadge(booking.status)}
                  
                  {booking.status === 'pending' && (
                    <button 
                      className="btn btn-danger"
                      onClick={() => handleCancelBooking(booking.id)}
                    >
                      Cancel Booking
                    </button>
                  )}
                  
                  {booking.status === 'active' && (
                    <button className="btn btn-secondary">
                      Extend Rental
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default MyBookings;
